```js
#!/usr/bin/env node
import Anthropic from '@anthropic-ai/sdk';
const client = new Anthropic(); // reads ANTHROPIC_API_KEY from env

const diff = process.argv[2];
if (!diff) {
  console.error('Usage: node pr-describe.mjs "<git diff>"');
  process.exit(1);
}

const res = await client.messages.create({
  model: 'claude-3-haiku-20240307',
  max_tokens: 300,
  system: 'You write clear pull request descriptions. Given a git diff, output: one line title, blank line, then 3-5 bullet points. Be concise and technical.',
  messages: [{ role: 'user', content: diff }]
});

console.log(res.content[0].text);
```

Save as `pr-describe.mjs`. Set `ANTHROPIC_API_KEY` in your shell. Run:
```bash
export ANTHROPIC_API_KEY=sk-ant-...
node pr-describe.mjs "$(git diff main)"
```

### minimist: the simplest arg parser

```bash
npm install minimist
```

```js
import minimist from 'minimist';
const args = minimist(process.argv.slice(2), {
  string: ['model', 'format'],
  boolean: ['verbose', 'json'],
  default: { model: 'haiku', format: 'text', verbose: false },
  alias: { v: 'verbose', m: 'model' }
});
// node tool.mjs input.txt -m sonnet --json
// args._      = ['input.txt']
// args.model  = 'sonnet'
// args.json   = true
```

### Two flags worth adding to every tool

**Model selection:**
```js
const MODEL_MAP = {
  haiku: 'claude-3-haiku-20240307',
  sonnet: 'claude-sonnet-4-6',
};
const model = MODEL_MAP[args.model] ?? MODEL_MAP.haiku;
// Default cheap, upgrade when needed: -m sonnet
```

**JSON output (for piping):**
```js
if (args.json) {
  console.log(JSON.stringify({ result: res.content[0].text }));
} else {
  console.log(res.content[0].text);
}
// node tool.mjs input.txt --json | jq '.result'
```

```js
// 1. Validate inputs first
if (!args._.length) {
  console.error('Error: No input provided.');
  console.error('Usage: node tool.mjs <file> [--model sonnet] [--json]');
  process.exit(1); // exit 1 = error (scripts can detect this)
}

// 2. Wrap API call
try {
  const res = await client.messages.create(...);
  console.log(res.content[0].text);
} catch (err) {
  if (err.status === 429) console.error('Rate limited — wait a moment and retry.');
  else if (err.status === 401) console.error('Bad API key. Check ANTHROPIC_API_KEY.');
  else if (err.status === 400) console.error('Bad request:', err.message);
  else console.error('Unexpected error:', err.message);
  process.exit(1);
}
```

Good error messages tell users exactly what went wrong and how to fix it.

### Two additions to make it a real CLI

**1. `bin` in package.json:**
```json
{
  "name": "pr-describe",
  "version": "1.0.0",
  "type": "module",
  "bin": { "pr-describe": "./index.mjs" }
}
```

**2. Shebang at top of script:**
```js
#!/usr/bin/env node
import Anthropic from '@anthropic-ai/sdk';
// ...
```

`bin` = command name → file mapping. Shebang = OS knows to run with Node. That's the entire recipe.

