### README structure that works:
1. What it does (1 sentence + example)
2. `npx your-tool` install/run
3. Setup: export API key
4. Copy-pasteable examples
5. All flags documented in a table

```js
import { readFile, writeFile } from 'fs/promises';
import { readdirSync } from 'fs';

// Read file from arg
const input = args._[0] ? await readFile(args._[0], 'utf-8') : null;
if (!input) { console.error('Provide a file path'); process.exit(1); }

// Process
const res = await client.messages.create({ /* ... */ });

// Write or print
if (args.output) {
  await writeFile(args.output, res.content[0].text, 'utf-8');
  console.error(`Saved to ${args.output}`); // stderr keeps stdout clean for piping
} else {
  process.stdout.write(res.content[0].text);
}
```

Output of call 1 becomes input of call 2:

```js
// Step 1: Extract key points
const step1 = await client.messages.create({
  model: 'claude-3-haiku-20240307', max_tokens: 200,
  system: 'Extract 5 key points from this document. One per line.',
  messages: [{ role: 'user', content: document }]
});

// Step 2: Generate quiz questions from key points
const step2 = await client.messages.create({
  model: 'claude-3-haiku-20240307', max_tokens: 400,
  system: 'Generate 5 quiz questions from these key points.',
  messages: [{ role: 'user', content: step1.content[0].text }]
});

if (args.verbose) console.error('Key points:', step1.content[0].text);
console.log(step2.content[0].text);
```

This is the foundation of agentic multi-step tools.

```js
const files = readdirSync('./docs').filter(f => f.endsWith('.md'));
console.error(`Processing ${files.length} files...`);

const results = [];
for (let i = 0; i < files.length; i += 5) {
  const batch = files.slice(i, i + 5);
  const batchResults = await Promise.all(batch.map(async (file) => {
    const content = await readFile(`./docs/${file}`, 'utf-8');
    const res = await client.messages.create({
      model: 'claude-3-haiku-20240307', max_tokens: 150,
      system: 'Summarize in 2 sentences.',
      messages: [{ role: 'user', content }]
    });
    return { file, summary: res.content[0].text };
  }));
  results.push(...batchResults);
  if (i + 5 < files.length) await new Promise(r => setTimeout(r, 1000));
  console.error(`${Math.min(i + 5, files.length)}/${files.length} done`);
}

await writeFile('summaries.json', JSON.stringify(results, null, 2));
console.error('Done.');
```
